code = """import json
import pandas as pd
import datetime

# Load Opportunities
opps_data = locals()['var_function-call-10477700483382465794']
# opps_data is a list of dicts

# Load Contracts
contracts_file = locals()['var_function-call-10477700483382466791']
with open(contracts_file, 'r') as f:
    contracts_data = json.load(f)

# Create DataFrames
df_opp = pd.DataFrame(opps_data)
df_cont = pd.DataFrame(contracts_data)

# Function to clean IDs
def clean_id(x):
    if x is None:
        return None
    x = str(x).strip()
    if x.startswith('#'):
        return x[1:]
    return x

# Clean IDs
df_opp['CleanContractId'] = df_opp['ContractID__c'].apply(clean_id)
df_opp['CleanOwnerId'] = df_opp['OwnerId'].apply(clean_id)
df_cont['CleanId'] = df_cont['Id'].apply(clean_id)

# Filter out Opps with no contract
df_opp = df_opp[df_opp['CleanContractId'].notna() & (df_opp['CleanContractId'] != 'None')]

# Merge
merged = pd.merge(df_opp, df_cont, left_on='CleanContractId', right_on='CleanId', how='inner')

# Calculate duration
# CreatedDate format: "2023-04-15T09:00:34.000+0000"
# CompanySignedDate format: "2023-06-13" (YYYY-MM-DD)

# We need to handle the date parsing carefully
# Use pd.to_datetime with utc=True for CreatedDate
merged['CreatedDateDT'] = pd.to_datetime(merged['CreatedDate'])
merged['SignedDateDT'] = pd.to_datetime(merged['CompanySignedDate'])

# Ensure timezones are handled. CompanySignedDate is naive (date only). 
# We should probably normalize CreatedDate to date only or make SignedDate TZ-aware.
# Simpler to converting CreatedDate to naive date (in UTC or local? usually doesn't matter much for days diff if margin is large, but to be precise let's just take the .date())

merged['CreatedDateOnly'] = merged['CreatedDateDT'].dt.date
merged['SignedDateOnly'] = merged['SignedDateDT'].dt.date

merged['Duration'] = (merged['SignedDateOnly'] - merged['CreatedDateOnly']).dt.days

# Group by OwnerId and calc average
result_df = merged.groupby('CleanOwnerId')['Duration'].mean().reset_index()
result_df = result_df.sort_values(by='Duration')

print("__RESULT__:")
print(result_df.to_json(orient='records'))"""

